            if (newCost < dist[i + 1][j][t]) {
                dist[i + 1][j][t] = newCost
                pq.add(LongArray(4).apply {
                    this[0] = newCost
                    this[1] = (i + 1).toLong()
                    this[2] = j.toLong()
                    this[3] = t.toLong()
                })
            }
        }

        // Teleportation
        if (t < k) {
            for (tele in teleportList[i][j]) {
                val x = tele[0]
                val y = tele[1]
                val newT = t + 1
                if (cost < dist[x][y][newT]) {
