class PriorityQueue {
    private heap: [number, number, number, number][] = [];

    enqueue(cost: number, i: number, j: number, t: number): void {
        const newEntry = [cost, i, j, t];
        this.heap.push(newEntry);
        this.heapifyUp(this.heap.length - 1);
    }

    dequeue(): [number, number, number, number] {
        if (this.heap.length === 0) return [0, 0, 0, 0];
        const min = this.heap[0];
        this.heap[0] = this.heap[this.heap.length - 1];
        this.heap.pop();
        this.heapifyDown(0);
        return min;
    }

    private heapifyUp(index: number): void {
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            if (this.heap[parentIndex][0] <= this.heap[index][0]) {
                break;
            }
            [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
            index = parentIndex;
        }
    }

    private heapifyDown(index: number): void {
        const n = this.heap.length;
        while (index < n) {
            const left = 2 * index + 1;
            const right = 2 * index + 2;
            let smallest = index;
            if (left < n && this.heap[left][0] < this.heap[smallest][0]) {
                smallest = left;
            }
            if (right < n && this.heap[right][0] < this.heap[smallest][0]) {
                smallest = right;
            }
            if (smallest === index) break;
            [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
            index = smallest;
        }
    }

    isEmpty(): boolean {
        return this.heap.length === 0;
    }
}

function solve(grid: number[][], k: number): number {
    const m = grid.length;
    const n = grid[0].length;

    const teleportList: (number[][])[] = [];
    for (let i = 0; i < m; i++) {
        teleportList[i] = [];
        for (let j = 0; j < n; j++) {
            const currentVal = grid[i][j];
            for (let x = 0; x < m; x++) {
                for (let y = 0; y < n; y++) {
                    if (grid[x][y] <= currentVal) {
                        teleportList[i][j].push([x, y]);
                    }
                }
            }
        }
    }

    const dist = new Array(m).fill(0).map(() => new Array(n).fill(0).map(() => new Array(k + 1).fill(Infinity)));
    dist[0][0][0] = 0;

    const pq = new PriorityQueue();
    pq.enqueue(0, 0, 0, 0);

    while (!pq.isEmpty()) {
        const [cost, i, j, t] = pq.dequeue();
        if (i === m - 1 && j === n - 1) {
            return cost;
        }
        if (cost > dist[i][j][t]) {
            continue;
        }

        // Regular moves: right and down
        if (j + 1 < n) {
            const newCost = cost + grid[i][j + 1];
            if (newCost < dist[i][j + 1][t]) {
                dist[i][j + 1][t] = newCost;
                pq.enqueue(newCost, i, j + 1, t);
            }
        }
        if (i + 1 < m) {
            const newCost = cost + grid[i + 1][j];
            if (newCost < dist[i + 1][j][t]) {
                dist[i + 1][j][t] = newCost;
                pq.enqueue(newCost, i + 1, j, t);
            }
        }

        // Teleportation
        if (t < k) {
            for (const [x, y] of teleportList[i][j]) {
                const newT = t + 1;
                if (cost < dist[x][y][newT]) {
                    dist[x][y][newT] = cost;
                    pq.enqueue(cost, x, y, newT);
                }
            }
        }
    }

    return -1;
}
